101→export function EmojiPickerView() {
102→  const nav = useNavigation();
103→  const [query, setQuery] = useState('');
104→  const [filterValue, setFilterValue] = useState('all');
105→  const [activeIndex, setActiveIndex] = useState(0);
106→  const [actionsOpen, setActionsOpen] = useState(false);
107→  const [recentChars, setRecentChars] = useState<string[]>(loadRecentEmojis);
108→  const { items: hudItems, show: showHUD } = useHUD();
109→  const containerRef = useRef<HTMLDivElement>(null);
110→
111→  const emojiLookup = useMemo(() => {
