157→      });
158→    }
159→
160→    const grouped = new Map<EmojiCategory, EmojiEntry[]>();
161→    for (const emoji of filtered) {
162→      const existing = grouped.get(emoji.category);
163→      if (existing) {
164→        existing.push(emoji);
165→      } else {
166→        grouped.set(emoji.category, [emoji]);
167→      }
168→    }
169→
170→    for (const cat of EMOJI_CATEGORY_ORDER) {
171→      const items = grouped.get(cat);
172→      if (items && items.length > 0) {
173→        result.push({
174→          title: EMOJI_CATEGORY_LABELS[cat],
175→          emojis: items,
176→        });
177→      }
178→    }
179→
180→    return result;
181→  }, [
182→    filtered,
183→    query,
184→    filterValue,
185→    recentEmojis,
186→  ]);
187→
188→  const flatEmojis = useMemo(() => sections.flatMap(s => s.emojis), [sections]);
189→  const totalCount = flatEmojis.length;
190→
191→  useEffect(() => {
192→    if (totalCount === 0) {
193→      setActiveIndex(0);
194→    } else if (activeIndex >= totalCount) {
195→      setActiveIndex(totalCount - 1);
196→    }
197→  }, [
198→    totalCount,
199→    activeIndex,
200→  ]);
201→
202→  useEffect(() => {
203→    const container = containerRef.current;
204→    if (!container) return;
205→    const el = container.querySelector<HTMLElement>(
206→      `[data-emoji-index="${activeIndex}"]`,
