414→function ExtensionsTab({
415→  extensions,
416→  onToggle,
417→  query,
418→}: {
419→  extensions: ExtensionEntry[];
420→  onToggle: (id: string) => void;
421→  query: string;
422→}) {
423→  const filtered = useMemo(() => {
424→    if (!query) return extensions;
425→    const lower = query.toLowerCase();
426→    return extensions.filter(
427→      ext =>
428→        ext.name.toLowerCase().includes(lower) ||
429→        ext.description.toLowerCase().includes(lower) ||
430→        ext.author.toLowerCase().includes(lower),
431→    );
432→  }, [
433→    extensions,
434→    query,
435→  ]);
436→
437→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
438→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
439→
440→  return (
441→    <div className="settings-view__extensions">
442→      {filtered.length === 0 ? (
443→        <EmptyState
444→          icon={<SearchEmptyIcon />}
445→          title="No Extensions Found"
446→          description="Try a different search term"
447→        />
448→      ) : (
449→        <>
450→          {raycastExts.length > 0 && (
451→            <div className="settings-section">
452→              <div className="settings-section__title">Built-in</div>
453→              {raycastExts.map(ext => (
454→                <ExtensionRow
455→                  key={ext.id}
456→                  ext={ext}
457→                  onToggle={onToggle}
458→                  showAuthor={false}
459→                />
460→              ))}
461→            </div>
462→          )}
463→          {communityExts.length > 0 && (
464→            <div className="settings-section">
465→              <div className="settings-section__title">Community</div>
466→              {communityExts.map(ext => (
467→                <ExtensionRow
468→                  key={ext.id}
469→                  ext={ext}
470→                  onToggle={onToggle}
471→                  showAuthor
472→                />
473→              ))}
474→            </div>
475→          )}
476→        </>
477→      )}
478→    </div>
479→  );
480→}
