 96→const SNIPPETS_KEY = 'snippets';
 97→
 98→interface StoredSnippet {
 99→  id: string;
100→  name: string;
101→  keyword: string;
102→  content: string;
103→  category: string;
104→  tags: {
105→    text: string;
106→    color?: string;
107→  }[];
108→  createdAt: string;
109→}
110→
111→function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
112→  if (!Array.isArray(value)) return false;
113→  return value.every(
114→    v =>
115→      isRecord(v) &&
116→      typeof v.id === 'string' &&
117→      typeof v.name === 'string' &&
118→      typeof v.keyword === 'string' &&
119→      typeof v.content === 'string' &&
120→      typeof v.category === 'string' &&
121→      typeof v.createdAt === 'string' &&
122→      Array.isArray(v.tags),
123→  );
124→}
125→
126→function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
127→  return entries.map(e => ({
128→    ...e,
129→    createdAt: e.createdAt.toISOString(),
130→  }));
131→}
132→
133→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
134→
135→function isTagColor(value: string): value is TagColor {
136→  return TAG_COLOR_NAMES.has(value);
137→}
138→
139→function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
140→  return stored.map(s => ({
141→    ...s,
142→    category: isSnippetCategory(s.category) ? s.category : 'general',
143→    tags: s.tags.map(t => ({
144→      text: t.text,
145→      color: t.color && isTagColor(t.color) ? t.color : undefined,
146→    })),
147→    createdAt: new Date(s.createdAt),
148→  }));
149→}
150→
151→function loadSnippets(): SnippetEntry[] {
152→  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
153→  if (stored) return deserializeEntries(stored);
154→  return MOCK_SNIPPET_ENTRIES;
155→}
156→
157→function saveSnippets(entries: SnippetEntry[]) {
158→  storageSet(SNIPPETS_KEY, serializeEntries(entries));
159→}
