473→            stroke="currentColor"
474→            strokeWidth="1.5"
475→            strokeLinecap="round"
476→            strokeLinejoin="round"
477→          />
478→        </svg>
479→      ),
480→      primaryAction: {
481→        label: 'Delete',
482→        style: 'destructive',
483→        onAction: () => {
