506→
507→  const handleFormSubmit = useCallback(
508→    (form: SnippetFormState) => {
509→      if (subView === 'edit' && editingSnippet) {
510→        setEntries(prev => {
511→          const next = prev.map(e =>
512→            e.id === editingSnippet.id
513→              ? {
514→                  ...e,
515→                  name: form.name,
