528→          saveSnippets(next);
529→          return next;
530→        });
531→        showHUD({
532→          icon: <SnippetHUDIcon />,
533→          title: 'Snippet Updated',
534→        });
535→      } else {
536→        const newEntry: SnippetEntry = {
537→          id: `snip-${Date.now()}`,
538→          name: form.name,
539→          keyword: form.keyword,
540→          content: form.snippet,
541→          category: form.category,
542→          tags: form.tags.map(t => {
543→            const found = SNIPPET_TAGS.find(st => st.value === t);
544→            return { text: found?.label ?? t };
545→          }),
546→          createdAt: new Date(),
547→        };
548→        setEntries(prev => {
549→          const next = [
550→            newEntry,
551→            ...prev,
552→          ];
553→          saveSnippets(next);
