              <Kbd
                keys={[
                  '⌘',
                  '⌫',
                ]}
              />
            ),
            onClick: handleDelete,
          },
        ],
      },
    ],
    [
      handleInsert,
      handleCopy,
      handleEdit,
      handleCreate,
      handleDelete,
    ],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  if (subView !== 'list') {
    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
    return (
